const agentOutput = $input.first().json.output || $input.first().json.text || '';

const CATEGORY_MAP = {
  'Food & Restaurant': 1, 'Fashion & Apparel': 2, 'Health & Wellness': 3,
  'Technology': 4, 'Beauty & Personal Care': 5, 'Art & Creative': 6,
  'Finance & Legal': 7, 'Education & Tutoring': 8, 'Freelancers': 9,
  'Handyman Services': 10, 'Transportation & Logistics': 11
};

let businesses = [];
try {
  const m = agentOutput.match(/\[\s*\{[\s\S]*?\}\s*\]/);
  businesses = JSON.parse(m ? m[0] : agentOutput.trim());
} catch (e) {
  return [{ json: { error: 'Failed to parse agent output', raw: agentOutput.slice(0, 800) } }];
}

if (!Array.isArray(businesses) || !businesses.length) {
  return [{ json: { error: 'No businesses found', raw: agentOutput.slice(0, 800) } }];
}

const seen = new Set();
return businesses
  .filter(biz => {
    if (!biz.name || !biz.website) return false;
    const key = String(biz.website).toLowerCase().replace(/^https?:\/\/(www\.)?/, '').replace(/\/$/, '');
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  })
  .map(biz => {
    const slug = (biz.name || '')
      .toLowerCase().trim().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-').slice(0, 48)
      + '-' + Math.random().toString(36).slice(2, 7);
    const website = String(biz.website || '').replace(/^https?:\/\/(www\.)?/, '').replace(/\/$/, '');
    return {
      json: {
        slug,
        name:             biz.name,
        category_id:      CATEGORY_MAP[biz.category] || 1,
        category_label:   biz.category || '',
        owner_name:       biz.owner_name      || null,
        city:             biz.city            || '',
        state_code:       String(biz.state_code || '').toUpperCase().slice(0, 2),
        location:         `${biz.city || ''}, ${String(biz.state_code || '').toUpperCase().slice(0, 2)}`,
        address:          biz.address         || null,
        phone:            biz.phone           || null,
        email:            biz.email           || null,
        website:          website             || null,
        hours:            biz.hours           || null,
        price_range:      ['$','$$','$$$','$$$$'].includes(biz.price_range) ? biz.price_range : '$$',
        rating:           0,
        review_count:     0,
        description:      biz.description     || null,
        image_url:        null,
        image_alt:        null,
        featured:         false,
        status:           'pending',
        lat:              typeof biz.lat === 'number' ? biz.lat : null,
        lng:              typeof biz.lng === 'number' ? biz.lng : null,
        minority_type:    biz.minority_type   || null,
        ownership_signal: biz.ownership_signal || null
      }
    };
  });

const biz = $input.first().json;

const websiteUrl = biz.website ? `https://${biz.website}` : null;

const prompt = `You are a minority business ownership verification specialist for Real Black Wall Street.

VERIFY whether this business is genuinely minority-owned:

Business: ${biz.name}
Category: ${biz.category_label}
Location: ${biz.address || biz.location}
Owner: ${biz.owner_name || 'unknown'}
Website: ${websiteUrl || 'none'}
Minority Type Claimed: ${biz.minority_type || 'not specified'}
Ownership Signal Found During Discovery: ${biz.ownership_signal || 'none'}
Description: ${biz.description || 'none'}

VERIFICATION STEPS (use your tools):
${websiteUrl ? `1. Use firecrawl_verify to scrape ${websiteUrl} — look for: About page, founder story, ownership statements, diversity certifications, "Black-owned", "minority-owned", "women-owned", "family-owned" mentions, founder photos or bios, NMSDC/WBENC/SBA 8(a) certification badges.` : '1. No website available — skip scraping.'}
${websiteUrl ? `2. Use firecrawl_verify to scrape ${websiteUrl}/about or ${websiteUrl}/about-us for ownership details.` : ''}
3. Use serper_verify to search: "${biz.name} ${biz.city || ''} minority owned" and "${biz.name} owner ${biz.owner_name || ''}"
4. Use serper_verify to search: "${biz.name} Black owned" OR "${biz.name} Hispanic owned" OR "${biz.name} women owned"

AFTER gathering evidence, respond with ONLY a valid JSON object:
{
  "verified": true or false,
  "confidence": number from 0 to 100,
  "minority_type": "Black | Hispanic | Asian | Women | Indigenous | Other | Unknown",
  "certification": "NMSDC | WBENC | SBA 8a | State Certified | Self-Identified | None",
  "evidence": "1–2 sentences describing exactly what evidence confirms or denies minority ownership",
  "verdict": "APPROVE | REJECT | NEEDS_REVIEW"
}

Verdict guide:
- APPROVE: verified = true, confidence >= 65 — clear evidence of minority ownership
- NEEDS_REVIEW: confidence 35–64 — some signals but not conclusive
- REJECT: verified = false, confidence < 35 — no credible evidence found

Return ONLY the JSON object. No markdown, no explanation.`;

return [{ json: { ...biz, verificationPrompt: prompt } }];

const biz = $input.first().json;
const raw = biz.output || biz.text || '';

let verdict = {};
try {
  const m = raw.match(/\{[\s\S]*?\}/);
  verdict = JSON.parse(m ? m[0] : raw.trim());
} catch (e) {
  verdict = { verified: false, confidence: 0, verdict: 'NEEDS_REVIEW', evidence: 'Could not parse verifier output.', minority_type: biz.minority_type || 'Unknown', certification: 'None' };
}

const finalMinorityType = verdict.minority_type || biz.minority_type || 'Unknown';
const prefix = finalMinorityType !== 'Unknown' ? `[${finalMinorityType}-owned] ` : '';
const desc = prefix + (biz.description || '');

return [{
  json: {
    ...biz,
    verified:        verdict.verified       || false,
    confidence:      verdict.confidence     || 0,
    verdict:         verdict.verdict        || 'NEEDS_REVIEW',
    evidence:        verdict.evidence       || '',
    certification:   verdict.certification  || 'None',
    minority_type:   finalMinorityType,
    short_desc:      desc.slice(0, 220) || null,
    description:     desc || null
  }
}];

const items = $input.all();
const date = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const approved     = items.filter(i => i.json.verdict === 'APPROVE');
const needsReview  = items.filter(i => i.json.verdict === 'NEEDS_REVIEW');

const renderList = (arr, color) => arr
  .map(i => i.json)
  .map(b => `<li style="margin-bottom:10px"><strong>${b.name}</strong> <span style="color:${color};font-size:11px">[${b.minority_type || 'Unknown'} · ${b.certification || 'None'} · ${b.confidence || 0}% confidence]</span><br><small style="color:#555">${b.city}, ${b.state_code} &nbsp;·&nbsp; ${b.website || 'no website'}</small><br><small style="color:#777;font-style:italic">${b.evidence || ''}</small></li>`)
  .join('');

const html = `<div style="font-family:sans-serif;max-width:680px">
  <h2 style="color:#22c55e;border-bottom:2px solid #22c55e;padding-bottom:8px">RBSW AI Discovery + Verification Report</h2>
  <p><strong>Date:</strong> ${date}</p>
  <table style="border-collapse:collapse;margin-bottom:20px">
    <tr><td style="padding:6px 16px 6px 0"><strong>✅ Approved (pending admin sign-off):</strong></td><td style="color:#16a34a;font-weight:700">${approved.length}</td></tr>
    <tr><td style="padding:6px 16px 6px 0"><strong>🔍 Needs Human Review:</strong></td><td style="color:#d97706;font-weight:700">${needsReview.length}</td></tr>
    <tr><td style="padding:6px 16px 6px 0"><strong>Total Inserted:</strong></td><td style="font-weight:700">${approved.length + needsReview.length}</td></tr>
  </table>
  ${approved.length ? `<h3 style="color:#16a34a">✅ Approved Listings</h3><ul style="padding-left:18px">${renderList(approved, '#16a34a')}</ul>` : ''}
  ${needsReview.length ? `<h3 style="color:#d97706">🔍 Needs Review (flagged for inspection)</h3><ul style="padding-left:18px">${renderList(needsReview, '#d97706')}</ul>` : ''}
  <hr style="margin:24px 0;border-color:#eee">
  <p style="font-size:12px;color:#888">All listings are <strong>status: pending</strong>. Use the Supabase dashboard or the existing RBSW approval workflow to approve or reject each one. &mdash; RBSW AI Business Scout</p>
</div>`;

return [{ json: { approved: approved.length, needsReview: needsReview.length, total: approved.length + needsReview.length, date, html } }];
